=== cargo and Nix definitions ===
[package]
name         = "spirit-judge"
version      = "0.1.0"
edition      = "2024"
rust-version = "1.89"
license      = "MIT OR Apache-2.0"
repository   = "https://github.com/LiGoldragon/spirit-judge"
description  = "Spirit judge text/model edge adapter."
publish      = false

[lib]
name = "spirit_judge"
path = "src/lib.rs"

[[bin]]
name = "spirit-judge"
path = "src/main.rs"

[features]
default = []
live-provider = ["judge/live-provider"]

[dependencies]
judge                = { git = "https://github.com/LiGoldragon/judge.git", rev = "dfba388b9fbf55468c6ae7f6b3b3520b6bebaad4" }
nota                 = { package = "nota", git = "https://github.com/LiGoldragon/nota.git", branch = "main" }
sha2                 = "0.10"
signal-frame         = { git = "https://github.com/LiGoldragon/signal-frame.git", branch = "main", default-features = false }
signal-spirit-judge  = { git = "https://github.com/LiGoldragon/signal-spirit-judge.git", rev = "7c25b71a34858c0d912dff8fd0b4f4ac213d7cd1", features = ["nota-text"] }
tempfile             = "3"
thiserror            = "2"
tokio                = { version = "1", features = ["rt-multi-thread", "macros", "net", "io-util", "time"] }

[dev-dependencies]
signal-spirit = { git = "https://github.com/LiGoldragon/signal-spirit.git", rev = "1cf7c010029de46369b742687da4fa1ca6def9a9", default-features = false, features = ["nota-text"] }

[lints.rust]
unsafe_code = "forbid"
unused      = { level = "warn", priority = -1 }
dead_code   = "warn"

[patch."https://github.com/LiGoldragon/nota-next.git"]
nota = { package = "nota", git = "https://github.com/LiGoldragon/nota.git", branch = "main" }
nota-derive = { package = "nota-derive", git = "https://github.com/LiGoldragon/nota.git", branch = "main" }
{
  description = "spirit-judge — Spirit judge text/model edge adapter";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";
    flake-utils.url = "github:numtide/flake-utils";
    rust-build = {
      url = "github:LiGoldragon/rust-build";
      inputs.nixpkgs.follows = "nixpkgs";
    };
  };

  outputs = { self, nixpkgs, flake-utils, rust-build }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = import nixpkgs { inherit system; };
        rust = rust-build.lib.${system}.fromToolchainFile pkgs {
          file = ./rust-toolchain.toml;
          sha256 = "sha256-gh/xTkxKHL4eiRXzWv8KP7vfjSk61Iq48x47BEDFgfk=";
        };
        inherit (rust) craneLib toolchain;
        src = rust.cleanSource { root = ./.; };
        commonArgs = { inherit src; strictDeps = true; };
        cargoArtifacts = craneLib.buildDepsOnly commonArgs;
        liveProviderCargoArtifacts = craneLib.buildDepsOnly (commonArgs // {
          cargoExtraArgs = "--features live-provider";
        });
      in
      {
        packages.default = craneLib.buildPackage (commonArgs // {
          cargoArtifacts = liveProviderCargoArtifacts;
          cargoExtraArgs = "--features live-provider";
        });
        checks = {
          build = craneLib.cargoBuild (commonArgs // { inherit cargoArtifacts; });
          test = craneLib.cargoTest (commonArgs // { inherit cargoArtifacts; });
          fmt = craneLib.cargoFmt { inherit src; };
          clippy = craneLib.cargoClippy (commonArgs // {
            inherit cargoArtifacts;
            cargoClippyExtraArgs = "--all-targets -- -D warnings";
          });
        };
        devShells.default = pkgs.mkShell {
          name = "spirit-judge";
          packages = [ pkgs.jujutsu pkgs.pkg-config toolchain ];
        };
      });
}
use std::path::PathBuf;

#[cfg(feature = "live-provider")]
use judge::{EndpointUrl, OpenAiCompatibleProviderClient};
use judge::{
    EnvironmentSecretResolver, FixtureProviderClient, OpenAiCodexProviderClient,
    ProviderAuthorization, ProviderCallTimeout, ProviderClient, ProviderModelName, ProviderName,
    ReasoningEffort, ResolvedProviderAuthorization, SecretSourceReference,
    SessionAuthorizationSourceReference,
};
use spirit_judge::{
    DEFAULT_LIVE_MODEL, SpiritJudgeAdapter, SpiritJudgeAdapterConfiguration,
    SpiritJudgeConfigurationPath, SpiritJudgeSocketPath, SpiritJudgeSocketServer,
};

#[tokio::main]
async fn main() {
    let result = match SpiritJudgeCommand::from_environment() {
        Ok(command) => command.run().await,
        Err(error) => Err(error),
    };
    if let Err(error) = result {
        eprintln!("spirit-judge: {error}");
        std::process::exit(1);
    }
}

#[derive(Debug)]
struct SpiritJudgeCommand {
    socket: PathBuf,
    config_root: Option<PathBuf>,
    provider: ProviderSelection,
    model: String,
    reasoning_effort: Option<ReasoningEffort>,
    provider_timeout_milliseconds: u64,
    endpoint: Option<String>,
    bearer_secret_source: Option<String>,
    external_authorization_source: Option<String>,
    session_launcher: Option<PathBuf>,
    codex_command: Option<PathBuf>,
    fixture_output: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum ProviderSelection {
    Fixture,
    OpenAiCompatible,
    OpenAiCodex,
}

impl SpiritJudgeCommand {
    fn from_environment() -> Result<Self, String> {
        let mut arguments = std::env::args().skip(1);
        let Some(command) = arguments.next() else {
            return Err(Self::usage());
        };
        if command != "serve" {
            return Err(Self::usage());
        }
        let mut socket = None;
        let mut config_root = None;
        let mut provider = std::env::var("SPIRIT_JUDGE_PROVIDER")
            .ok()
            .map(|value| ProviderSelection::from_name(&value))
            .transpose()?;
        let mut model =
            std::env::var("SPIRIT_JUDGE_MODEL").unwrap_or_else(|_| DEFAULT_LIVE_MODEL.to_owned());
        let mut reasoning_effort = std::env::var("SPIRIT_JUDGE_REASONING_EFFORT")
            .ok()
            .map(|value| Self::reasoning_effort_from_name(&value))
            .transpose()?;
        let mut provider_timeout_milliseconds =
            std::env::var("SPIRIT_JUDGE_PROVIDER_TIMEOUT_MILLISECONDS")
                .ok()
                .map(|value| value.parse::<u64>().map_err(|_| Self::usage()))
                .transpose()?
                .unwrap_or(180000);
        let mut endpoint = std::env::var("SPIRIT_JUDGE_PROVIDER_ENDPOINT").ok();
        let mut bearer_secret_source = std::env::var("SPIRIT_JUDGE_BEARER_SECRET_SOURCE").ok();
        let mut external_authorization_source =
            std::env::var("SPIRIT_JUDGE_EXTERNAL_AUTHORIZATION_SOURCE").ok();
        let mut session_launcher =
            std::env::var_os("SPIRIT_JUDGE_SESSION_LAUNCHER").map(PathBuf::from);
        let mut codex_command = std::env::var_os("SPIRIT_JUDGE_CODEX_COMMAND").map(PathBuf::from);
        let mut fixture_output = None;
        while let Some(argument) = arguments.next() {
            match argument.as_str() {
                "--socket" => socket = arguments.next().map(PathBuf::from),
                "--config-root" => config_root = arguments.next().map(PathBuf::from),
                "--provider" => {
                    provider = Some(ProviderSelection::from_name(
                        &arguments.next().ok_or_else(Self::usage)?,
                    )?)
                }
                "--endpoint" => endpoint = Some(arguments.next().ok_or_else(Self::usage)?),
                "--model" => model = arguments.next().ok_or_else(Self::usage)?,
                "--reasoning-effort" => {
                    reasoning_effort = Some(Self::reasoning_effort_from_name(
                        &arguments.next().ok_or_else(Self::usage)?,
                    )?)
                }
                "--provider-timeout-milliseconds" => {
                    provider_timeout_milliseconds = arguments
                        .next()
                        .ok_or_else(Self::usage)?
                        .parse::<u64>()
                        .map_err(|_| Self::usage())?
                }
                "--bearer-secret-source" => {
                    bearer_secret_source = Some(arguments.next().ok_or_else(Self::usage)?)
                }
                "--external-authorization-source" => {
                    external_authorization_source = Some(arguments.next().ok_or_else(Self::usage)?)
                }
                "--session-launcher" => {
                    session_launcher =
                        Some(PathBuf::from(arguments.next().ok_or_else(Self::usage)?))
                }
                "--codex-command" => {
                    codex_command = Some(PathBuf::from(arguments.next().ok_or_else(Self::usage)?))
                }
                "--fixture-output" => {
                    fixture_output = Some(arguments.next().ok_or_else(Self::usage)?);
                    provider = Some(ProviderSelection::Fixture);
                }
                _ => return Err(Self::usage()),
            }
        }
        Ok(Self {
            socket: socket.ok_or_else(Self::usage)?,
            config_root,
            provider: provider.unwrap_or(ProviderSelection::OpenAiCompatible),
            model,
            reasoning_effort,
            provider_timeout_milliseconds,
            endpoint,
            bearer_secret_source,
            external_authorization_source,
            session_launcher,
            codex_command,
            fixture_output,
        })
    }

    async fn run(self) -> Result<(), String> {
        let configuration_root =
            SpiritJudgeConfigurationPath::from_environment_or(self.config_root.clone())
                .map_err(|error| error.to_string())?;
        let provider_name = ProviderName::unchecked(self.provider.provider_name());
        let authorization = self.resolved_authorization()?;
        self.validate_provider_authorization(&authorization)?;
        let client = self.provider_client()?;
        let adapter = SpiritJudgeAdapter::new(
            SpiritJudgeAdapterConfiguration::new(
                configuration_root,
                provider_name,
                ProviderModelName::unchecked(self.model),
                self.reasoning_effort,
                authorization,
            ),
            client,
        );
        SpiritJudgeSocketServer::new(SpiritJudgeSocketPath::new(self.socket), adapter)
            .serve()
            .await
            .map_err(|error| error.to_string())
    }

    fn resolved_authorization(&self) -> Result<ResolvedProviderAuthorization, String> {
        let authorization = match (
            &self.bearer_secret_source,
            &self.external_authorization_source,
        ) {
            (Some(_), Some(_)) => {
                return Err(
                    "judge provider cannot combine bearer and external authorization".to_owned(),
                );
            }
            (Some(reference), None) => ProviderAuthorization::bearer_secret_source(
                SecretSourceReference::new(reference).map_err(|error| error.to_string())?,
            ),
            (None, Some(reference)) => ProviderAuthorization::external_session(
                SessionAuthorizationSourceReference::new(reference)
                    .map_err(|error| error.to_string())?,
            ),
            (None, None) => ProviderAuthorization::no_secret(),
        };
        authorization
            .resolve(&EnvironmentSecretResolver)
            .map_err(|error| error.to_string())
    }

    fn validate_provider_authorization(
        &self,
        authorization: &ResolvedProviderAuthorization,
    ) -> Result<(), String> {
        if self.provider != ProviderSelection::OpenAiCodex {
            return Ok(());
        }
        let ResolvedProviderAuthorization::ExternalSession(reference) = authorization else {
            return Err(
                "OpenAI Codex requires the codex-login external session reference".to_owned(),
            );
        };
        if reference.as_str() != "codex-login" {
            return Err("OpenAI Codex external session reference is unsupported".to_owned());
        }
        Ok(())
    }

    fn provider_client(&self) -> Result<Box<dyn ProviderClient>, String> {
        match self.provider {
            ProviderSelection::Fixture => Ok(Box::new(FixtureProviderClient::from_text(
                self.fixture_output
                    .clone()
                    .unwrap_or_else(|| "Accept".to_owned()),
            ))),
            ProviderSelection::OpenAiCompatible => self.openai_compatible_client(),
            ProviderSelection::OpenAiCodex => self.openai_codex_client(),
        }
=== existing client and tests ===
        let mut bytes = Vec::with_capacity(4 + length);
        bytes.extend_from_slice(&prefix);
        bytes.resize(4 + length, 0);
        stream
            .read_exact(&mut bytes[4..])
            .await
            .map_err(Error::Socket)?;
        Ok(bytes)
    }
}

pub struct SpiritJudgeClient {
    socket_path: SpiritJudgeSocketPath,
}

impl SpiritJudgeClient {
    pub fn new(socket_path: SpiritJudgeSocketPath) -> Self {
        Self { socket_path }
    }

    pub async fn submit(&self, request: SpiritJudgeRequest) -> Result<SpiritJudgeReply, Error> {
        let mut stream = UnixStream::connect(self.socket_path.as_path())
            .await
            .map_err(Error::Socket)?;
        let exchange = ClientExchange::first().identifier();
        let request = Request::from_payload(request);
        let frame = SpiritJudgeFrame::with_short_header(
            request.short_header(),
            ExchangeFrameBody::Request { exchange, request },
        );
        FrameTransport::write_frame(&mut stream, &frame).await?;
        let frame = FrameTransport::read_frame(&mut stream).await?;
        ClientExchange::reply_from_frame(frame)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct ClientExchange {
    session_epoch: SessionEpoch,
    sequence: LaneSequence,
}

impl ClientExchange {
    fn first() -> Self {
        Self {
            session_epoch: SessionEpoch::new(1),
            sequence: LaneSequence::first(),
        }
    }

    fn identifier(&self) -> ExchangeIdentifier {
        ExchangeIdentifier::new(self.session_epoch, ExchangeLane::Connector, self.sequence)
    }

    fn reply_from_frame(frame: SpiritJudgeFrame) -> Result<SpiritJudgeReply, Error> {
        match frame.into_body() {
            ExchangeFrameBody::Reply { reply, .. } => match reply {
                Reply::Accepted { per_operation, .. } => {
                    Ok(per_operation.into_head().representative_reply())
                }
                Reply::Rejected { reason } => Err(Error::Frame(reason.to_string())),
            },
            ExchangeFrameBody::HandshakeRequest(_) => {
                Err(Error::UnexpectedFrame("handshake request"))
            }
            ExchangeFrameBody::HandshakeReply(_) => Err(Error::UnexpectedFrame("handshake reply")),
            ExchangeFrameBody::Request { .. } => Err(Error::UnexpectedFrame("request")),
        }
    }
}

