        bytes.extend_from_slice(&prefix);
        bytes.resize(4 + length, 0);
        stream
            .read_exact(&mut bytes[4..])
            .await
            .map_err(Error::Socket)?;
        Ok(bytes)
    }
}

pub struct SpiritJudgeClient {
    socket_path: SpiritJudgeSocketPath,
}

impl SpiritJudgeClient {
    pub fn new(socket_path: SpiritJudgeSocketPath) -> Self {
        Self { socket_path }
    }

    pub async fn submit(&self, request: SpiritJudgeRequest) -> Result<SpiritJudgeReply, Error> {
        let mut stream = UnixStream::connect(self.socket_path.as_path())
            .await
            .map_err(Error::Socket)?;
        let exchange = ClientExchange::first().identifier();
        let request = Request::from_payload(request);
        let frame = SpiritJudgeFrame::with_short_header(
            request.short_header(),
            ExchangeFrameBody::Request { exchange, request },
        );
        FrameTransport::write_frame(&mut stream, &frame).await?;
        let frame = FrameTransport::read_frame(&mut stream).await?;
        ClientExchange::reply_from_frame(frame)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
struct ClientExchange {
    session_epoch: SessionEpoch,
    sequence: LaneSequence,
}

impl ClientExchange {
    fn first() -> Self {
        Self {
            session_epoch: SessionEpoch::new(1),
            sequence: LaneSequence::first(),
        }
    }

    fn identifier(&self) -> ExchangeIdentifier {
        ExchangeIdentifier::new(self.session_epoch, ExchangeLane::Connector, self.sequence)
    }

    fn reply_from_frame(frame: SpiritJudgeFrame) -> Result<SpiritJudgeReply, Error> {
        match frame.into_body() {
            ExchangeFrameBody::Reply { reply, .. } => match reply {
                Reply::Accepted { per_operation, .. } => {
                    Ok(per_operation.into_head().representative_reply())
                }
                Reply::Rejected { reason } => Err(Error::Frame(reason.to_string())),
            },
            ExchangeFrameBody::HandshakeRequest(_) => {
                Err(Error::UnexpectedFrame("handshake request"))
            }
            ExchangeFrameBody::HandshakeReply(_) => Err(Error::UnexpectedFrame("handshake reply")),
            ExchangeFrameBody::Request { .. } => Err(Error::UnexpectedFrame("request")),
        }
    }
}

