use spirit_judge::{
    SpiritJudgeAdapter, SpiritJudgeAdapterConfiguration, SpiritJudgeConfigurationPath,
};

#[test]
fn adapter_configuration_names_external_prompt_root() {
    let configuration = SpiritJudgeAdapterConfiguration::new(
        SpiritJudgeConfigurationPath::new("/tmp/spirit-judge-config").unwrap(),
        judge::ProviderName::new("provider").unwrap(),
        judge::ProviderModelName::new("model").unwrap(),
        None,
        judge::ResolvedProviderAuthorization::no_secret(),
    );
    let adapter = SpiritJudgeAdapter::new(
        configuration,
        judge::FixtureProviderClient::from_text("Accept"),
    );

    assert_eq!(
        adapter.configuration().configuration_path().as_path(),
        std::path::Path::new("/tmp/spirit-judge-config")
    );
}
# spirit-judge — architecture

`spirit-judge` is the Spirit-specific text/model edge adapter for model-backed
Spirit admission and referent-registration judgment.

It sits between the typed `signal-spirit-judge` request/reply contract and the
provider-facing mechanics in `judge`. It reads prompt/config data from an
external `spirit-judge-config` checkout or package path at runtime, lowers typed
