//! Spirit-specific judge adapter.
//!
//! `spirit-judge` is the text/model edge: it renders typed
//! `signal-spirit-judge` requests as prompt text, calls a provider through
//! `judge`, parses provider NOTA verdicts back into typed Spirit judge replies,
//! and serves the contract over a Unix socket.

#![forbid(unsafe_code)]

use std::path::{Path, PathBuf};
use std::time::Duration;

use judge::{
    ProviderCallReply, ProviderCallRequest, ProviderClient, ProviderMessage, ProviderModelName,
    ProviderName, ReasoningEffort, ResolvedProviderAuthorization,
};
use nota::{NotaDecode, NotaEncode, NotaSource};
use sha2::{Digest, Sha256};
use signal_frame::{
    ExchangeFrameBody, ExchangeIdentifier, ExchangeLane, LaneSequence, NonEmpty, Reply, Request,
    SessionEpoch, ShortHeader, SubReply,
};
use signal_spirit_judge::{
    AdmissionJudgeOperation, AdmissionJudgePacket, AdmissionJudgeResponse, AdmissionJudgeVerdict,
    AdmissionRejectionReason, ContentHash, JudgeDiagnostic, JudgmentScope, RedactedText,
    ReferentRegistrationJudgePacket, ReferentRegistrationJudgeResponse,
    ReferentRegistrationJudgeVerdict, ReferentRegistrationRejectionReason, SpiritJudgeFrame,
    SpiritJudgeReply, SpiritJudgeRequest, SpiritJudgeRequestRejection,
    SpiritJudgeRequestRejectionReason,
};
use thiserror::Error;
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::net::{UnixListener, UnixStream};
use tokio::time::timeout;

pub const DEFAULT_LIVE_MODEL: &str = "chatgpt-5.4-mini";

const ADMISSION_PROMPT_PATHS: &[&str] = &[
    "prompts/intent-admission/role.md",
    "prompts/intent-admission/record-shape.md",
    "prompts/intent-admission/justification-shape.md",
    "prompts/intent-admission/burden-ladder.md",
    "prompts/intent-admission/checklist.md",
    "prompts/intent-admission/rejection-reasons.md",
    "prompts/intent-admission/nota-output.md",
    "prompts/intent-admission/few-shot.md",
    "prompts/retry-instruction.md",
    "prompts/diagnostics.md",
];
const ADMISSION_USER_TEMPLATE_PATH: &str = "prompts/intent-admission/user-template.md";
const REFERENT_SYSTEM_PROMPT_PATH: &str = "prompts/referent-registration/system.md";
const REFERENT_USER_TEMPLATE_PATH: &str = "prompts/referent-registration/user-template.md";
const RETRY_INSTRUCTION_PATH: &str = "prompts/retry-instruction.md";
const DIAGNOSTICS_PROMPT_PATH: &str = "prompts/diagnostics.md";

pub type AdapterRequest = SpiritJudgeRequest;
pub type AdapterReply = SpiritJudgeReply;

#[derive(Debug, Error)]
pub enum Error {
    #[error("spirit judge config path is empty")]
    EmptyConfigurationPath,

    #[error("read prompt: {0}")]
    ReadPrompt(std::io::Error),

    #[error("provider call failed: {0}")]
    Provider(#[from] judge::Error),

    #[error("response parse failed: {0}")]
    ResponseParse(String),

    #[error("socket unavailable: {0}")]
    Socket(std::io::Error),

    #[error("frame failed: {0}")]
    Frame(String),

    #[error("unexpected frame: {0}")]
    UnexpectedFrame(&'static str),
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct SpiritJudgeConfigurationPath(PathBuf);

impl SpiritJudgeConfigurationPath {
    pub fn new(path: impl Into<PathBuf>) -> Result<Self, Error> {
        let path = path.into();
        if path.as_os_str().is_empty() {
            return Err(Error::EmptyConfigurationPath);
        }
        Ok(Self(path))
    }

    pub fn from_environment_or(path: Option<PathBuf>) -> Result<Self, Error> {
        match path {
            Some(path) => Self::new(path),
            None => Self::new(
                std::env::var_os("SPIRIT_JUDGE_CONFIG")
                    .map(PathBuf::from)
                    .unwrap_or_else(|| PathBuf::from(".")),
            ),
        }
    }

    pub fn as_path(&self) -> &Path {
        self.0.as_path()
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct SpiritJudgeAdapterConfiguration {
    configuration_path: SpiritJudgeConfigurationPath,
    provider_name: ProviderName,
    model_name: ProviderModelName,
    reasoning_effort: Option<ReasoningEffort>,
    authorization: ResolvedProviderAuthorization,
}

impl SpiritJudgeAdapterConfiguration {
    pub fn new(
        configuration_path: SpiritJudgeConfigurationPath,
        provider_name: ProviderName,
        model_name: ProviderModelName,
        reasoning_effort: Option<ReasoningEffort>,
        authorization: ResolvedProviderAuthorization,
    ) -> Self {
        Self {
            configuration_path,
            provider_name,
            model_name,
            reasoning_effort,
            authorization,
        }
    }

    pub fn fixture(configuration_path: SpiritJudgeConfigurationPath) -> Self {
        Self::new(
            configuration_path,
            ProviderName::unchecked("fixture"),
            ProviderModelName::unchecked(DEFAULT_LIVE_MODEL),
            None,
            ResolvedProviderAuthorization::no_secret(),
        )
    }

    pub fn configuration_path(&self) -> &SpiritJudgeConfigurationPath {
        &self.configuration_path
    }

    pub fn provider_name(&self) -> &ProviderName {
        &self.provider_name
    }

    pub fn model_name(&self) -> &ProviderModelName {
        &self.model_name
    }

    pub fn reasoning_effort(&self) -> Option<ReasoningEffort> {
        self.reasoning_effort
    }

    pub fn authorization(&self) -> &ResolvedProviderAuthorization {
        &self.authorization
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct PromptPack {
    system_text: String,
    user_template: String,
}

impl PromptPack {
    pub fn read_admission(
        configuration_path: &SpiritJudgeConfigurationPath,
    ) -> Result<Self, Error> {
        let sections = ADMISSION_PROMPT_PATHS
            .iter()
            .map(|path| PromptFile::new(path).read_from(configuration_path))
            .collect::<Result<Vec<_>, _>>()?;
        Ok(Self {
            system_text: sections.join("\n\n"),
            user_template: PromptFile::new(ADMISSION_USER_TEMPLATE_PATH)
                .read_from(configuration_path)?,
