#[cfg(test)]
mod tests {
    use std::time::Duration;

    use judge::FixtureProviderClient;
    use signal_spirit::schema::signal::{
        Aliases, Certainty, CommitSequence, Description, Domains, Entry, Importance, Justification,
        Kind, Magnitude, Privacy, Reasoning, Referent, Referents, StateDigest, Testimony,
    };
    use signal_spirit_judge::{
        DatabaseMarker, RecordRequest, RecordSet, ReferentRegistration, RegisteredReferents,
    };
    use tempfile::TempDir;

    use super::*;

    struct TestConfiguration {
        temporary: TempDir,
        root: SpiritJudgeConfigurationPath,
    }

    impl TestConfiguration {
        fn new() -> Self {
            let temporary = TempDir::new().unwrap();
            Self::write_admission_prompts(temporary.path());
            Self::write_referent_prompts(temporary.path());
            let root = SpiritJudgeConfigurationPath::new(temporary.path()).unwrap();
            Self { temporary, root }
        }

        fn root(&self) -> SpiritJudgeConfigurationPath {
            let _keep = self.temporary.path();
            self.root.clone()
        }

        fn write_admission_prompts(root: &Path) {
            for path in ADMISSION_PROMPT_PATHS {
                let full_path = root.join(path);
                std::fs::create_dir_all(full_path.parent().unwrap()).unwrap();
                std::fs::write(full_path, format!("section {path}")).unwrap();
            }
            let template_path = root.join(ADMISSION_USER_TEMPLATE_PATH);
            std::fs::create_dir_all(template_path.parent().unwrap()).unwrap();
            std::fs::write(
                template_path,
                "Operation: {operation}\nCandidate: {candidate}\nRecords: {bundle}\n{retry_instruction}",
            )
            .unwrap();
        }

        fn write_referent_prompts(root: &Path) {
            for path in [
                REFERENT_SYSTEM_PROMPT_PATH,
                REFERENT_USER_TEMPLATE_PATH,
                RETRY_INSTRUCTION_PATH,
                DIAGNOSTICS_PROMPT_PATH,
            ] {
                let full_path = root.join(path);
                std::fs::create_dir_all(full_path.parent().unwrap()).unwrap();
                let text = match path {
                    REFERENT_SYSTEM_PROMPT_PATH => "accept {accept}; reject {reject}",
                    REFERENT_USER_TEMPLATE_PATH => {
                        "registration {registration}; registered {registered_referents}; {retry_instruction}"
                    }
                    _ => "section",
                };
                std::fs::write(full_path, text).unwrap();
            }
        }
    }

    #[test]
    fn adapter_configuration_names_external_prompt_root() {
        let configuration = SpiritJudgeAdapterConfiguration::new(
            SpiritJudgeConfigurationPath::new("/tmp/spirit-judge-config").unwrap(),
            judge::ProviderName::new("provider").unwrap(),
            judge::ProviderModelName::new("model").unwrap(),
            None,
            judge::ResolvedProviderAuthorization::no_secret(),
        );
        let adapter = SpiritJudgeAdapter::new(
            configuration,
            judge::FixtureProviderClient::from_text("Accept"),
        );

        assert_eq!(
            adapter.configuration().configuration_path().as_path(),
            std::path::Path::new("/tmp/spirit-judge-config")
        );
    }

    #[test]
    fn fixture_provider_accepts_admission_through_adapter() {
        let configuration = TestConfiguration::new();
        let adapter = SpiritJudgeAdapter::new(
            SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
            FixtureProviderClient::from_text("Accept"),
        );

        let reply = adapter.judge(SpiritJudgeRequest::JudgeAdmission(SelfPacket::admission()));

        assert!(matches!(
            reply,
            SpiritJudgeReply::AdmissionJudged(AdmissionJudgeResponse {
                verdict: AdmissionJudgeVerdict::Accept,
                ..
            })
        ));
    }

    #[test]
    fn admission_rejection_explanation_becomes_public_diagnostic() {
        let configuration = TestConfiguration::new();
        let adapter = SpiritJudgeAdapter::new(
            SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
            FixtureProviderClient::from_text(
                "(Reject (Overstated [the evidence cannot clear the requested certainty]))",
            ),
        );

        let reply = adapter.judge(SpiritJudgeRequest::JudgeAdmission(SelfPacket::admission()));

        let SpiritJudgeReply::AdmissionJudged(response) = reply else {
            panic!("expected admission response");
        };
        assert!(matches!(
            response.verdict,
            AdmissionJudgeVerdict::Reject(AdmissionRejectionReason::Overstated)
        ));
        assert_eq!(
            response.diagnostic.redacted_text.as_str(),
            "the evidence cannot clear the requested certainty"
        );
    }

    #[test]
    fn private_rejection_diagnostic_is_redacted_and_hashed() {
        let configuration = TestConfiguration::new();
        let adapter = SpiritJudgeAdapter::new(
            SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
            FixtureProviderClient::from_text("(Reject (Matter [private raw detail]))"),
        );

        let mut packet = SelfPacket::admission();
        packet.scope = JudgmentScope::private_hashes_and_redaction();
        let reply = adapter.judge(SpiritJudgeRequest::JudgeAdmission(packet));

        let SpiritJudgeReply::AdmissionJudged(response) = reply else {
            panic!("expected admission response");
        };
        assert_eq!(
            response.diagnostic.redacted_text.as_str(),
            "private model diagnostic redacted"
        );
        assert_eq!(response.diagnostic.content_hashes.len(), 1);
    }

    #[test]
    fn fixture_provider_accepts_referent_registration_through_adapter() {
        let configuration = TestConfiguration::new();
        let adapter = SpiritJudgeAdapter::new(
            SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
            FixtureProviderClient::from_text("Accept"),
        );

        let reply = adapter.judge(SpiritJudgeRequest::JudgeReferentRegistration(
            SelfPacket::referent_registration(),
        ));

        assert!(matches!(
            reply,
            SpiritJudgeReply::ReferentRegistrationJudged(ReferentRegistrationJudgeResponse {
                verdict: ReferentRegistrationJudgeVerdict::Accept,
                ..
            })
        ));
    }

    #[test]
    fn malformed_provider_text_maps_to_request_rejection_without_raw_output() {
        let configuration = TestConfiguration::new();
        let adapter = SpiritJudgeAdapter::new(
            SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
            FixtureProviderClient::from_text("private raw provider echo"),
        );

        let reply = adapter.judge(SpiritJudgeRequest::JudgeAdmission(SelfPacket::admission()));

        let SpiritJudgeReply::RequestRejected(rejection) = reply else {
            panic!("expected request rejection");
        };
        assert_eq!(
            rejection.reason,
            SpiritJudgeRequestRejectionReason::ResponseFormatFailure
        );
        assert_eq!(
            rejection.diagnostic.redacted_text.as_str(),
            "model response did not match Spirit admission judge NOTA shape"
        );
        assert!(
            !rejection
                .diagnostic
                .redacted_text
                .as_str()
                .contains("private raw provider echo")
        );
        assert_eq!(rejection.diagnostic.content_hashes.len(), 1);
    }

    #[tokio::test]
    async fn unix_socket_frame_exchange_succeeds() {
        let configuration = TestConfiguration::new();
        let socket = configuration.temporary.path().join("spirit-judge.sock");
        let server = SpiritJudgeSocketServer::new(
            SpiritJudgeSocketPath::new(&socket),
            SpiritJudgeAdapter::new(
                SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
                FixtureProviderClient::from_text("Accept"),
            ),
        );
        let server_task = tokio::spawn(server.serve_one());
        tokio::time::sleep(Duration::from_millis(25)).await;
        let client = SpiritJudgeClient::new(SpiritJudgeSocketPath::new(socket));

        let reply = client
            .submit(SpiritJudgeRequest::JudgeAdmission(SelfPacket::admission()))
            .await
            .unwrap();
        let served_reply = server_task.await.unwrap().unwrap();

        assert_eq!(reply, served_reply);
        assert!(matches!(reply, SpiritJudgeReply::AdmissionJudged(_)));
    }

    #[tokio::test]
    async fn persistent_socket_server_handles_requests_after_an_idle_period() {
        let configuration = TestConfiguration::new();
        let socket = configuration
            .temporary
            .path()
            .join("persistent-spirit-judge.sock");
        let server = SpiritJudgeSocketServer::new(
            SpiritJudgeSocketPath::new(&socket),
            SpiritJudgeAdapter::new(
                SpiritJudgeAdapterConfiguration::fixture(configuration.root()),
                FixtureProviderClient::from_text("Accept"),
            ),
        );
        let server_task = tokio::spawn(server.serve());
        tokio::time::sleep(Duration::from_millis(25)).await;
        let client = SpiritJudgeClient::new(SpiritJudgeSocketPath::new(socket));

        for _ in 0..2 {
            let reply = client
                .submit(SpiritJudgeRequest::JudgeAdmission(SelfPacket::admission()))
                .await
                .unwrap();
            assert!(matches!(reply, SpiritJudgeReply::AdmissionJudged(_)));
            tokio::time::sleep(Duration::from_millis(75)).await;
        }

        server_task.abort();
    }

    struct SelfPacket;

    impl SelfPacket {
        fn admission() -> AdmissionJudgePacket {
            AdmissionJudgePacket::new(
                JudgmentScope::public(),
                AdmissionJudgeOperation::Record(Self::record_request()),
                RecordSet::new(Vec::new()),
                Self::database_marker(),
            )
        }

        fn referent_registration() -> ReferentRegistrationJudgePacket {
            ReferentRegistrationJudgePacket::new(
