use std::path::PathBuf;

use signal_spirit::schema::signal::{
    Certainty, CommitSequence, DatabaseMarker, Description, Domains, Entry, Importance,
    Justification, Kind, Magnitude, Privacy, Reasoning, RecordRequest, RecordSet, Referents,
    StateDigest, Testimony,
};
use signal_spirit_judge::{
    AdmissionJudgeOperation, AdmissionJudgePacket, AdmissionJudgeVerdict, JudgmentScope,
    SpiritJudgeReply, SpiritJudgeRequest,
};

use crate::{Error, SpiritJudgeClient, SpiritJudgeSocketPath};

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct WitnessMetadata {
    model: String,
    effort: String,
    revision: String,
}

impl WitnessMetadata {
    pub fn new(model: impl Into<String>, effort: impl Into<String>, revision: impl Into<String>) -> Self {
        Self {
            model: model.into(),
            effort: effort.into(),
            revision: revision.into(),
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct WitnessRequest {
    socket_path: PathBuf,
    metadata: WitnessMetadata,
}

impl WitnessRequest {
    pub fn new(socket_path: impl Into<PathBuf>, metadata: WitnessMetadata) -> Self {
        Self {
            socket_path: socket_path.into(),
            metadata,
        }
    }

    pub fn metadata(&self) -> WitnessMetadata {
        self.metadata.clone()
    }

    pub async fn submit(&self) -> Result<WitnessReport, Error> {
        let reply = SpiritJudgeClient::new(SpiritJudgeSocketPath::new(&self.socket_path))
            .submit(Self::synthetic_admission())
            .await?;
        Ok(WitnessReport::from_reply(self.metadata.clone(), reply))
    }

    fn synthetic_admission() -> SpiritJudgeRequest {
        SpiritJudgeRequest::JudgeAdmission(AdmissionJudgePacket::new(
            JudgmentScope::public(),
            AdmissionJudgeOperation::Record(RecordRequest {
                entry: Entry {
                    domains: Domains::new(Vec::new()),
                    kind: Kind::Principle,
                    description: Description::new("Synthetic component compatibility witness."),
                    certainty: Certainty::new(Magnitude::High),
                    importance: Importance::new(Magnitude::Medium),
                    privacy: Privacy::new(Magnitude::Zero),
                    referents: Referents::new(Vec::new()),
                },
                justification: Justification {
                    testimony: Testimony::new(Vec::new()),
                    reasoning: Reasoning::new("Synthetic non-database socket witness."),
                },
            }),
            RecordSet::new(Vec::new()),
            DatabaseMarker {
                commit_sequence: CommitSequence::new(0),
                state_digest: StateDigest::new(0),
            },
        ))
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum WitnessVerdictClass {
    Accept,
    Reject,
    RequestRejected,
    Unavailable,
}

impl WitnessVerdictClass {
    fn as_str(&self) -> &'static str {
        match self {
            Self::Accept => "accept",
            Self::Reject => "reject",
            Self::RequestRejected => "request-rejected",
            Self::Unavailable => "unavailable",
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct WitnessReport {
    metadata: WitnessMetadata,
    verdict_class: WitnessVerdictClass,
}

impl WitnessReport {
    pub fn unavailable(metadata: WitnessMetadata) -> Self {
        Self {
            metadata,
            verdict_class: WitnessVerdictClass::Unavailable,
        }
    }

    pub fn verdict_class(&self) -> WitnessVerdictClass {
        self.verdict_class
    }

    pub fn exit_status(&self) -> i32 {
        match self.verdict_class {
            WitnessVerdictClass::Accept | WitnessVerdictClass::Reject => 0,
            WitnessVerdictClass::RequestRejected | WitnessVerdictClass::Unavailable => 1,
        }
    }

    pub fn render(&self) -> String {
        format!(
            "(SpiritJudgeWitness (VerdictClass {}) (Model {}) (Effort {}) (Revision {}) (ExitStatus {}))",
            self.verdict_class.as_str(),
            self.metadata.model,
            self.metadata.effort,
            self.metadata.revision,
            self.exit_status(),
        )
    }

    fn from_reply(metadata: WitnessMetadata, reply: SpiritJudgeReply) -> Self {
        let verdict_class = match reply {
            SpiritJudgeReply::AdmissionJudged(response) => match response.verdict {
                AdmissionJudgeVerdict::Accept => WitnessVerdictClass::Accept,
                AdmissionJudgeVerdict::Reject(_) => WitnessVerdictClass::Reject,
            },
            SpiritJudgeReply::ReferentRegistrationJudged(_) | SpiritJudgeReply::RequestRejected(_) => {
                WitnessVerdictClass::RequestRejected
            }
        };
        Self {
            metadata,
            verdict_class,
        }
    }
}

use std::path::PathBuf;
use std::process::ExitCode;

use spirit_judge::{WitnessMetadata, WitnessReport, WitnessRequest};

#[tokio::main]
async fn main() -> ExitCode {
    let command = match WitnessCommand::from_environment() {
        Ok(command) => command,
        Err(usage) => {
            eprintln!("{usage}");
            return ExitCode::FAILURE;
        }
    };
    command.run().await
}

#[derive(Debug)]
struct WitnessCommand {
    request: WitnessRequest,
}

impl WitnessCommand {
    fn from_environment() -> Result<Self, &'static str> {
        let mut arguments = std::env::args_os().skip(1);
        let mut socket = None;
        let mut model = None;
        let mut effort = None;
        let mut revision = None;
        while let Some(argument) = arguments.next() {
            match argument.to_str() {
                Some("--socket") => socket = arguments.next().map(PathBuf::from),
                Some("--model") => model = arguments.next().and_then(|value| value.into_string().ok()),
                Some("--effort") => effort = arguments.next().and_then(|value| value.into_string().ok()),
                Some("--revision") => {
                    revision = arguments.next().and_then(|value| value.into_string().ok())
                }
                _ => return Err(Self::usage()),
            }
        }
        let metadata = WitnessMetadata::new(
            model.ok_or_else(Self::usage)?,
            effort.ok_or_else(Self::usage)?,
            revision.ok_or_else(Self::usage)?,
        );
        Ok(Self {
            request: WitnessRequest::new(socket.ok_or_else(Self::usage)?, metadata),
        })
    }

    async fn run(self) -> ExitCode {
        let report = match self.request.submit().await {
            Ok(report) => report,
            Err(_) => WitnessReport::unavailable(self.request.metadata()),
        };
        println!("{}", report.render());
        ExitCode::from(report.exit_status() as u8)
    }

    fn usage() -> &'static str {
        "usage: spirit-judge-witness --socket <path> --model <name> --effort <level> --revision <immutable-revision>"
    }
}

