arguments.content:
use std::path::Path;
use std::time::Duration;

use judge::FixtureProviderClient;
use signal_spirit_judge::SpiritJudgeReply;
use spirit_judge::{
    SpiritJudgeAdapter, SpiritJudgeAdapterConfiguration, SpiritJudgeConfigurationPath,
    SpiritJudgeSocketPath, SpiritJudgeSocketServer, WitnessMetadata, WitnessRequest,
    WitnessVerdictClass,
};
use tempfile::TempDir;

struct FixtureConfiguration {
    temporary: TempDir,
    root: SpiritJudgeConfigurationPath,
}

impl FixtureConfiguration {
    fn new() -> Self {
        let temporary = TempDir::new().unwrap();
        Self::write_admission_prompts(temporary.path());
        let root = SpiritJudgeConfigurationPath::new(temporary.path()).unwrap();
        Self { temporary, root }
    }

    fn socket(&self) -> std::path::PathBuf {
        self.temporary.path().join("spirit-judge-witness.sock")
    }

    fn root(&self) -> SpiritJudgeConfigurationPath {
        self.root.clone()
    }

    fn write_admission_prompts(root: &Path) {
        for path in [
            "prompts/intent-admission/role.md",
            "prompts/intent-admission/record-shape.md",
            "prompts/intent-admission/justification-shape.md",
            "prompts/intent-admission/burden-ladder.md",
            "prompts/intent-admission/checklist.md",
            "prompts/intent-admission/rejection-reasons.md",
            "prompts/intent-admission/nota-output.md",
            "prompts/intent-admission/few-shot.md",
            "prompts/retry-instruction.md",
            "prompts/diagnostics.md",
        ] {
            let full_path = root.join(path);
            std::fs::create_dir_all(full_path.parent().unwrap()).unwrap();
            std::fs::write(full_path, format!("section {path}")).unwrap();
        }
        let template_path = root.join("prompts/intent-admission/user-template.md");
        std::fs::create_dir_all(template_path.parent().unwrap()).unwrap();
        std::fs::write(
            template_path,
            "Operation: {operation}\nCandidate: {candidate}\nRecords: {bundle}\n{retry_instruction}",
        )
        .unwrap();
    }
}

struct FixtureServer {
    configuration: FixtureConfiguration,
    provider_output: &'static str,
}

impl FixtureServer {
    fn new(provider_output: &'static str) -> Self {
        Self {
            configuration: FixtureConfiguration::new(),
            provider_output,
        }
    }

    async fn serve_one(&self) -> SpiritJudgeReply {
        let socket = self.configuration.socket();
        let server = SpiritJudgeSocketServer::new(
            SpiritJudgeSocketPath::new(&socket),
            SpiritJudgeAdapter::new(
                SpiritJudgeAdapterConfiguration::fixture(self.configuration.root()),
                FixtureProviderClient::from_text(self.provider_output),
            ),
        );
        let server_task = tokio::spawn(server.serve_one());
        tokio::time::sleep(Duration::from_millis(25)).await;
        let report = WitnessRequest::new(
            socket,
            WitnessMetadata::new("fixture-model", "medium", "fixture-revision"),
        )
        .submit()
        .await
        .unwrap();
        let _served_reply = server_task.await.unwrap().unwrap();
        report
    }
}

#[tokio::test]
async fn witness_uses_typed_socket_with_fixture_provider_and_renders_only_metadata() {
    let report = FixtureServer::new("Accept").serve_one().await;

    assert_eq!(report.verdict_class(), WitnessVerdictClass::Accept);
    assert_eq!(report.exit_status(), 0);
    assert_eq!(
        report.render(),
        "(SpiritJudgeWitness (VerdictClass accept) (Model fixture-model) (Effort medium) (Revision fixture-revision) (ExitStatus 0))"
    );
}

#[tokio::test]
async fn witness_does_not_render_fake_provider_output_or_diagnostic() {
    let report = FixtureServer::new("provider output that must not escape").serve_one().await;

    assert_eq!(report.verdict_class(), WitnessVerdictClass::RequestRejected);
    assert_eq!(report.exit_status(), 1);
    assert!(!report.render().contains("provider output that must not escape"));
}

